/**
 * Semantic color roles exposed by each built-in app theme.
 *
 * These colors represent the visual identity of a theme and are used for
 * swatch previews in the theme picker. Actual runtime rendering is driven by
 * CSS custom properties injected by the theme system in the web app.
 */
export interface ThemeColors {
  /** Main application background surface. */
  background: string;
  /** Primary text / foreground color. */
  foreground: string;
  /** Brand accent / interactive highlight color. */
  accent: string;
  /** Navigation sidebar background. */
  sidebar: string;
  /** Code editor area background. */
  editor: string;
  /** Integrated terminal background. */
  terminal: string;
  /** Status bar / bottom bar background. */
  statusBar: string;
}

/** Identifier for a built-in named theme. */
export type ThemeId = "t3-light" | "t3-dark" | "t3-midnight";

/**
 * Stored theme preference.
 * A concrete named theme, or "system" to follow the OS dark/light setting
 * (which auto-resolves to "t3-dark" on dark OS or "t3-light" on light OS).
 */
export type ThemePreference = ThemeId | "system";

/** A built-in application theme definition. */
export interface AppTheme {
  /** Unique theme identifier. */
  readonly id: ThemeId;
  /** Human-readable display name shown in the theme picker. */
  readonly name: string;
  /** Short description shown in the theme picker. */
  readonly description: string;
  /** Base color mode driving the dark/light CSS variant for this theme. */
  readonly colorMode: "light" | "dark";
  /**
   * Preview swatch colors reflecting the visual identity of the theme.
   * These are display-only; they are not directly applied as CSS custom
   * properties — see the theme system in apps/web for that mapping.
   */
  readonly colors: ThemeColors;
}

/** All built-in themes, in the order they appear in the theme picker. */
export const BUILT_IN_THEMES: readonly AppTheme[] = [
  {
    id: "t3-light",
    name: "T3 Light",
    description: "A clean, high-contrast light theme.",
    colorMode: "light",
    colors: {
      background: "#ffffff",
      foreground: "#1c1917",
      accent: "#7c3aed",
      sidebar: "#f5f3ff",
      editor: "#fafafa",
      terminal: "#f0f0f5",
      statusBar: "#ede9fe",
    },
  },
  {
    id: "t3-dark",
    name: "T3 Dark",
    description: "A refined dark theme with deep purple accents.",
    colorMode: "dark",
    colors: {
      background: "#0d0d11",
      foreground: "#e8e8f0",
      accent: "#8b5cf6",
      sidebar: "#09090d",
      editor: "#0d0d11",
      terminal: "#060609",
      statusBar: "#1a1630",
    },
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    description: "Deep midnight blue for late-night focus sessions.",
    colorMode: "dark",
    colors: {
      background: "#06080f",
      foreground: "#c4d4ee",
      accent: "#3b82f6",
      sidebar: "#040610",
      editor: "#06080f",
      terminal: "#030508",
      statusBar: "#0c1525",
    },
  },
] as const;

