import { useCallback, useEffect, useSyncExternalStore } from "react";
import { BUILT_IN_THEMES, type ThemeId, type ThemePreference } from "@t3tools/contracts";

export type { ThemeId, ThemePreference };

const STORAGE_KEY = "t3code:theme:v2";
/** Legacy key written by the old light/dark/system toggle — migrated on first read. */
const LEGACY_STORAGE_KEY = "t3code:theme";
const SYSTEM_DARK_QUERY = "(prefers-color-scheme: dark)";

type ThemeSnapshot = {
  preference: ThemePreference;
  /** Only meaningful when preference === "system". */
  systemDark: boolean;
};

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return typeof window !== "undefined" && window.matchMedia(SYSTEM_DARK_QUERY).matches;
}

const VALID_PREFERENCES = new Set<string>(["system", ...BUILT_IN_THEMES.map((t) => t.id)]);

function getStoredPreference(): ThemePreference {
  if (typeof window === "undefined") return "system";

  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && VALID_PREFERENCES.has(raw)) return raw as ThemePreference;

  // Migrate from the old "t3code:theme" key (values: "light" | "dark" | "system").
  const legacy = localStorage.getItem(LEGACY_STORAGE_KEY);
  if (legacy === "dark") return "t3-dark";
  if (legacy === "light") return "t3-light";
  if (legacy === "system") return "system";

  return "system";
}

function resolveThemeId(preference: ThemePreference, systemDark: boolean): ThemeId {
  if (preference === "system") return systemDark ? "t3-dark" : "t3-light";
  return preference;
}

/**
 * Apply a theme preference to the document root.
 *
 * Sets the `.dark` color-mode class and a `.theme-{id}` class used by
 * per-theme CSS overrides. Optionally suppresses transitions for the
 * duration of the switch to avoid a flash of animated color change.
 */
function applyTheme(preference: ThemePreference, suppressTransitions = false): void {
  if (typeof window === "undefined") return;

  const systemDark = getSystemDark();
  const themeId = resolveThemeId(preference, systemDark);
  const appTheme = BUILT_IN_THEMES.find((t) => t.id === themeId) ?? BUILT_IN_THEMES[1]!;
  const isDark = appTheme.colorMode === "dark";

  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Toggle dark color-mode class.
  root.classList.toggle("dark", isDark);

  // Toggle named theme class — exactly one at a time.
  for (const t of BUILT_IN_THEMES) {
    root.classList.toggle(`theme-${t.id}`, t.id === themeId);
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class is in effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash of wrong theme.
applyTheme(getStoredPreference());

function getSnapshot(): ThemeSnapshot {
  const preference = getStoredPreference();
  const systemDark = preference === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.preference === preference &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { preference, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Re-apply and notify when the OS color-scheme preference changes.
  const mq = window.matchMedia(SYSTEM_DARK_QUERY);
  const handleMqChange = () => {
    if (getStoredPreference() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleMqChange);

  // Re-apply and notify when another tab changes the stored preference.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStoredPreference(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleMqChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { preference, systemDark } = snapshot;

  const themeId = resolveThemeId(preference, systemDark);
  const appTheme = BUILT_IN_THEMES.find((t) => t.id === themeId) ?? BUILT_IN_THEMES[1]!;

  /**
   * The base color mode of the active theme.
   * Kept as `"light" | "dark"` for backward-compatibility with consumers
   * such as the diff renderer and syntax highlighter.
   */
  const resolvedTheme: "light" | "dark" = appTheme.colorMode;

  const setTheme = useCallback((next: ThemePreference) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep the DOM in sync whenever the preference changes (e.g. after hydration).
  useEffect(() => {
    applyTheme(preference);
  }, [preference]);

  return {
    /** Stored theme preference — a ThemeId or "system". */
    theme: preference,
    /** Set the stored preference and immediately apply the theme. */
    setTheme,
    /**
     * Resolved base color mode ("light" | "dark").
     * For consumers that only need to know which color-mode is active
     * (e.g. diff renderers, syntax highlighters).
     */
    resolvedTheme,
    /** The fully resolved ThemeId currently applied to the document. */
    resolvedThemeId: themeId,
    /** All built-in theme definitions, for use by theme picker UIs. */
    themes: BUILT_IN_THEMES,
  } as const;
}

