/* ─── T3 Midnight theme ──────────────────────────────────────────────────────
 * Applied when the user picks "T3 Midnight". Overrides the dark-mode CSS
 * custom properties with a deep blue-black palette and blue accent.
 * The .dark class is always co-present when this theme is active.
 * ─────────────────────────────────────────────────────────────────────────── */
:root.dark.theme-t3-midnight {
  --background: oklch(0.09 0.025 228);
  --foreground: oklch(0.82 0.04 228);
  --card: oklch(0.1 0.025 228);
  --card-foreground: oklch(0.82 0.04 228);
  --popover: oklch(0.1 0.025 228);
  --popover-foreground: oklch(0.82 0.04 228);
  --primary: oklch(0.62 0.18 228);
  --primary-foreground: var(--color-white);
  --secondary: --alpha(var(--color-white) / 4%);
  --secondary-foreground: oklch(0.82 0.04 228);
  --muted: --alpha(var(--color-white) / 4%);
  --muted-foreground: oklch(0.62 0.05 228);
  --accent: --alpha(var(--color-white) / 4%);
  --accent-foreground: oklch(0.82 0.04 228);
  --destructive: color-mix(in srgb, var(--color-red-500) 90%, var(--color-white));
  --destructive-foreground: var(--color-red-400);
  --border: --alpha(var(--color-white) / 6%);
  --input: --alpha(var(--color-white) / 8%);
  --ring: oklch(0.62 0.18 228);
  --info: var(--color-blue-400);
  --info-foreground: var(--color-blue-300);
  --success: var(--color-emerald-500);
  --success-foreground: var(--color-emerald-400);
  --warning: var(--color-amber-500);
  --warning-foreground: var(--color-amber-400);
}

