import { BUILT_IN_THEMES, type AppTheme, type ThemePreference } from "@t3tools/contracts";
import { useTheme } from "~/hooks/useTheme";

// ─── Swatch previews ──────────────────────────────────────────────────────────

/**
 * Renders a miniature layout preview using the theme's color palette.
 * The layout mimics the app shell: a narrow sidebar on the left, an editor
 * area in the upper-right, a terminal strip in the lower-right, and a
 * thin status bar across the bottom.
 */
function ThemeSwatchPreview({ colors }: { colors: AppTheme["colors"] }) {
  return (
    <div
      aria-hidden="true"
      className="relative h-10 w-full overflow-hidden rounded-md"
      style={{ background: colors.background }}
    >
      {/* Sidebar */}
      <div
        className="absolute bottom-0 left-0 top-0 w-[28%]"
        style={{ background: colors.sidebar }}
      />
      {/* Editor area */}
      <div
        className="absolute left-[28%] right-0 top-0"
        style={{ bottom: "26%", background: colors.editor }}
      />
      {/* Terminal strip */}
      <div
        className="absolute left-[28%] right-0"
        style={{ top: "74%", bottom: "14%", background: colors.terminal }}
      />
      {/* Status bar */}
      <div
        className="absolute bottom-0 left-0 right-0 h-[14%]"
        style={{ background: colors.statusBar }}
      />
      {/* Accent dot — represents interactive / brand color */}
      <div
        className="absolute left-[31%] top-[10%] h-[18%] w-[18%] rounded-sm opacity-90"
        style={{ background: colors.accent }}
      />
    </div>
  );
}

/**
 * Swatch preview for the "System" pseudo-option.
 * Shows the light theme on the left half and the dark theme on the right half
 * to communicate that the choice adapts to the OS setting.
 */
function SystemSwatchPreview() {
  const light = BUILT_IN_THEMES.find((t) => t.id === "t3-light")!;
  const dark = BUILT_IN_THEMES.find((t) => t.id === "t3-dark")!;
  return (
    <div aria-hidden="true" className="relative h-10 w-full overflow-hidden rounded-md">
      {/* Left half — light */}
      <div
        className="absolute bottom-0 left-0 top-0 w-1/2"
        style={{ background: light.colors.background }}
      >
        <div
          className="absolute bottom-0 left-0 top-0 w-[28%]"
          style={{ background: light.colors.sidebar }}
        />
        <div
          className="absolute bottom-[14%] left-[28%] right-0 top-0"
          style={{ background: light.colors.editor }}
        />
        <div
          className="absolute bottom-0 left-[28%] right-0 h-[14%]"
          style={{ background: light.colors.statusBar }}
        />
      </div>
      {/* Right half — dark */}
      <div
        className="absolute bottom-0 right-0 top-0 w-1/2"
        style={{ background: dark.colors.background }}
      >
        <div
          className="absolute bottom-0 left-0 top-0 w-[28%]"
          style={{ background: dark.colors.sidebar }}
        />
        <div
          className="absolute bottom-[14%] left-[28%] right-0 top-0"
          style={{ background: dark.colors.editor }}
        />
        <div
          className="absolute bottom-0 left-[28%] right-0 h-[14%]"
          style={{ background: dark.colors.statusBar }}
        />
      </div>
      {/* Divider */}
      <div className="absolute bottom-0 left-1/2 top-0 w-px bg-black/20" />
    </div>
  );
}

// ─── Option card ──────────────────────────────────────────────────────────────

interface ThemeOptionProps {
  preference: ThemePreference;
  name: string;
  description: string;
  selected: boolean;
  resolvedWhenSystem?: string;
  onSelect: () => void;
  preview: React.ReactNode;
}

function ThemeOption({
  preference,
  name,
  description,
  selected,
  resolvedWhenSystem,
  onSelect,
  preview,
}: ThemeOptionProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      aria-label={`${name} theme${resolvedWhenSystem ? ` (currently resolves to ${resolvedWhenSystem})` : ""}`}
      onClick={onSelect}
      className={[
        "group flex flex-col gap-2 rounded-xl border p-2.5 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
        selected
          ? "border-primary/60 bg-primary/8"
          : "border-border bg-background hover:bg-accent/50",
      ].join(" ")}
    >
      {/* Color swatch */}
      <div
        className={[
          "w-full overflow-hidden rounded-lg ring-1 transition-shadow",
          selected ? "ring-primary/40" : "ring-border",
        ].join(" ")}
      >
        {preview}
      </div>

      {/* Label row */}
      <div className="flex min-w-0 items-center justify-between gap-1.5">
        <div className="min-w-0">
          <p
            className={[
              "truncate text-xs font-medium",
              selected ? "text-foreground" : "text-muted-foreground group-hover:text-foreground",
            ].join(" ")}
          >
            {name}
          </p>
          <p className="truncate text-[10px] text-muted-foreground/70">{description}</p>
        </div>
        {selected && (
          <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[9px] font-semibold uppercase tracking-wider text-primary">
            Active
          </span>
        )}
      </div>
    </button>
  );
}

// ─── Public component ─────────────────────────────────────────────────────────

/**
 * Theme picker grid with color swatch previews.
 *
 * Renders one card per built-in theme plus a "System" pseudo-option that
 * follows the OS dark/light preference. Selecting a card immediately applies
 * the theme and persists the choice to localStorage.
 */
export function ThemeSelector() {
  const { theme, setTheme, resolvedThemeId, themes } = useTheme();

  return (
    <div className="space-y-3">
      <div
        className="grid grid-cols-2 gap-2 sm:grid-cols-4"
        role="radiogroup"
        aria-label="Theme preference"
      >
        {/* System option — resolves based on OS preference */}
        <ThemeOption
          preference="system"
          name="System"
          description="Follow OS setting"
          selected={theme === "system"}
          resolvedWhenSystem={
            theme === "system"
              ? themes.find((t) => t.id === resolvedThemeId)?.name
              : undefined
          }
          onSelect={() => setTheme("system")}
          preview={<SystemSwatchPreview />}
        />

        {/* Named built-in themes */}
        {themes.map((appTheme) => (
          <ThemeOption
            key={appTheme.id}
            preference={appTheme.id}
            name={appTheme.name}
            description={appTheme.description}
            selected={theme === appTheme.id}
            onSelect={() => setTheme(appTheme.id)}
            preview={<ThemeSwatchPreview colors={appTheme.colors} />}
          />
        ))}
      </div>

      <p className="text-xs text-muted-foreground">
        Active:{" "}
        <span className="font-medium text-foreground">
          {theme === "system"
            ? `System (${themes.find((t) => t.id === resolvedThemeId)?.name ?? resolvedThemeId})`
            : (themes.find((t) => t.id === theme)?.name ?? theme)}
        </span>
      </p>
    </div>
  );
}

